namespace BgControls.Windows.Input.Touch;/// <summary>/// 触控选择器控件，用于在触控交互中显示选择状态的视觉反馈./// </summary>[TemplateVisualState(Name = StateNormal, GroupName = StateGroupName)][TemplateVisualState(Name = StateCenter, GroupName = StateGroupName)][TemplateVisualState(Name = StateHidden, GroupName = StateGroupName)]public class TouchSelector : Control{    private const string StateGroupName = "Common";    private const string StateNormal = "Normal";    private const string StateHidden = "Hidden";    private const string StateCenter = "Center";    /// <summary>    /// Initializes static members of the <see cref="TouchSelector"/> class.    /// </summary>    static TouchSelector()    {        // 覆盖默认样式键以确保加载正确的控件模板.        FrameworkElement.DefaultStyleKeyProperty.OverrideMetadata(typeof(TouchSelector), new FrameworkPropertyMetadata(typeof(TouchSelector)));    }    private TouchSelectorState currentState;    /// <summary>    /// Initializes a new instance of the <see cref="TouchSelector"/> class.    /// </summary>    protected internal TouchSelector()    {        // 设置控件不可获取焦点，防止干扰正常的键盘/触控焦点流转.        this.Focusable = false;        // 初始状态设置为隐藏.        this.SetState(TouchSelectorState.Hidden);    }    /// <summary>    /// Gets 当前选择器的状态.    /// </summary>    protected internal TouchSelectorState State => this.currentState;    /// <summary>    /// 控件初始化时的处理逻辑.    /// </summary>    /// <param name="e">事件参数.</param>    protected override void OnInitialized(EventArgs e)    {        base.OnInitialized(e);    }    /// <summary>    /// 应用控件模板时的处理逻辑.    /// </summary>    public override void OnApplyTemplate()    {        base.OnApplyTemplate();        // 在应用模板后重新应用当前状态，以确保视觉状态机（VisualStateManager）正确切换.        this.SetState(this.currentState);    }    /// <summary>    /// 设置选择器的状态并触发视觉状态切换.    /// </summary>    /// <param name="state">目标选择器状态.</param>    protected internal void SetState(TouchSelectorState state)    {        this.currentState = state;        // 根据状态枚举切换到对应的视觉状态.        switch (this.currentState)        {            case TouchSelectorState.Normal:                this.GoToState(StateNormal);                break;            case TouchSelectorState.Center:                this.GoToState(StateCenter);                break;            default:                this.GoToState(StateHidden);                break;        }    }    /// <summary>    /// 设置选择器在画布中的位置.    /// </summary>    /// <param name="position">目标坐标点.</param>    protected internal void SetPosition(Point position)    {        // 使用 Canvas 附加属性设置坐标.        Canvas.SetLeft(this, position.X);        Canvas.SetTop(this, position.Y);    }    /// <summary>    /// 隐藏当前选择器.    /// </summary>    protected internal void Hide()    {        this.SetState(TouchSelectorState.Hidden);    }    /// <summary>    /// 执行视觉状态切换逻辑.    /// </summary>    /// <param name="stateName">视觉状态名称.</param>    private void GoToState(string stateName)    {        // 触发视觉状态管理器进行状态转换.        VisualStateManager.GoToState(this, stateName, useTransitions: true);    }}